// Error Workflow -- Global Dead-Letter + Alert (S03, 201, 202)
// Receives the error payload from any failed execution of the main workflow.

const error = $input.first().json;

// Snapshot what we can from the partial execution
const runId = error.execution?.id || 'unknown';
const workflowId = error.workflow?.id || 'unknown';
const errorMessage = error.error?.message || String(error.error || 'unknown');
const errorNode = error.error?.node?.name || 'unknown';
const lastData = error.execution?.lastNodeExecuted || {};
const leadSnapshot = lastData.json || {};

// Derive lead idempotency key from snapshot if present
const dedupeKey = leadSnapshot.idempotency_key || leadSnapshot.dedupe || null;

const output = {
  error: {
    message: errorMessage,
    node: errorNode,
    run_id: runId,
    workflow_id: workflowId
  },
  lead_snapshot: {
    dedupe_key: dedupeKey,
    name: leadSnapshot.name || null,
    email: leadSnapshot.email || null,
    raw: JSON.stringify(leadSnapshot).slice(0, 2000)
  },
  stage: errorNode,
  alerted_at: new Date().toISOString()
};

return [{ json: output }];

// Dead-Letter Writer (201, 202)
// Writes a row to the dead_letter table with full context.

const { Pool } = require('pg');
const DATABASE_URL = process.env.DATABASE_URL || 'postgresql://postgres:postgres@localhost:5432/intake_pipeline';
const pool = new Pool({ connectionString: DATABASE_URL, connectionTimeoutMillis: 5000 });

const input = $input.first().json;
const client = await pool.connect();

try {
  await client.query('BEGIN');
  const sql = `INSERT INTO dead_letter
    (idempotency_key, stage, error_message, lead_snapshot, run_id, created_at)
    VALUES ($1, $2, $3, $4, $5, NOW())
    RETURNING id`;
  const values = [
    input.lead_snapshot?.dedupe_key || 'unknown',
    input.stage || 'unknown',
    input.error?.message || 'unknown',
    JSON.stringify(input.lead_snapshot || {}),
    input.error?.run_id || 'unknown'
  ];
  const result = await client.query(sql, values);
  await client.query('COMMIT');
  input.dlq_id = result.rows[0]?.id;
} catch (dbErr) {
  input.errors = input.errors || [];
  input.errors.push({ stage: 'dlq_write', message: dbErr.message });
} finally {
  client.release();
}

return [{ json: input }];

